pub(crate) fn relation_weight(relation: &str) -> f32 {
    match relation {
        "implements" => 0.9,
        "extends" => 0.85,
        "calls" => 0.7,
        "imports" => 0.5,
        "uses" => 0.4,
        "contains" => 0.3,
        "references" => 0.2,
        _ => 0.5, // unknown relations get neutral weight
    }
}
